// JavaScript
import '@maersk-global/mds-components-core/mc-drawer';
import '@maersk-global/mds-components-core/mc-button';

const mcDrawer = document.querySelector('mc-drawer');

drawer.customsize = {
  xs: '100%',
  sm: '300px',
  md: '400px',
  lg: '500px',
  xl: '600px',
}
const toggleDrawer = () => {
  const drawer = document.querySelector('mc-drawer');
  if (drawer) {
    drawer.open = !drawer.open;
  }
};

// HTML
<mc-drawer position="left">
  <span slot="heading">Responsive Drawer</span>
  <div>This drawer has responsive width based on breakpoints. To use responsive height, please change the position to top/bottom.</div>
  <mc-button slot="footer" dialogaction="close">Close</mc-drawer>
</mc-drawer>
<mc-button onclick="toggleDrawer()">Open drawer</mc-button>

advanced.WithDrawer:
// JavaScript
import '@maersk-global/mds-components-core/mc-drawer';
import '@maersk-global/mds-components-core/mc-button';
import '@maersk-global/mds-components-core/mc-toast';
import '@maersk-global/mds-components-core/mc-notification';
import '@maersk-global/mds-components-core/mc-input';
import '@maersk-global/mds-components-core/mc-input-date';

const toggleDrawer = () => {
  const mcDrawer: IMcDrawer = document.body.querySelector('mc-drawer') as IMcDrawer;
  mcDrawer.open = true;
};
const toggleToast = () => {
  const toast = document.body.querySelector('mc-toast');
  toast.open = true;
};

const mcButtonOpenDrawer = document.getElementById('openDrawer') as HTMLButtonElement;
mcButtonOpenDrawer.addEventListener('click', () => toggleDrawer());

const mcButtonShowToast = document.getElementById('showToast') as HTMLButtonElement;
mcButtonShowToast.addEventListener('click', () => toggleToast());

// HTML
<mc-toast duration="5000" position="bottom-right" appearance="error">
  <mc-notification body="Toast body text"></mc-notification>
</mc-toast>
<mc-button id="openDrawer">Open drawer</mc-button>
<mc-drawer heading="Heading" customstacking>
  <div class="mds-flex mds-flex-column mds-gap-400">
    <mc-button
      id="showToast"
      label="Click to show toast"
      appearance="neutral"
      variant="outlined"
    ></mc-button>
    <mc-input autofocus label="Input in drawer"></mc-input>
    <mc-input-date label="Input date in drawer"></mc-input-date>
    <a href="https://designsystem.maersk.com" target="_blank" rel="noopener noreferrer">Design System</a>
  </div>
  <mc-button slot="footer" dialogaction="close" appearance="primary">Close</mc-button>
</mc-drawer>
